    59→
    60→*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    61→
    62→a, button { -webkit-tap-highlight-color: transparent; }
    63→
    64→html {
    65→  scroll-behavior: smooth;
    66→  scroll-padding-top: calc(var(--nav-height) + 16px);
