     1→<!DOCTYPE html>
     2→<html lang="en">
     3→<head>
     4→<meta charset="UTF-8"/>
     5→<meta name="viewport" content="width=device-width, initial-scale=1.0"/>
     6→<title>Ollama Model Catalog 2025</title>
     7→<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;0,900;1,400;1,700&family=IBM+Plex+Mono:ital,wght@0,400;0,500;0,600;1,400&family=DM+Sans:wght@300;400;500;600&display=swap" rel="stylesheet"/>
     8→<style>
     9→:root {
    10→  --paper:      #FAF8F4;
    11→  --page:       #F3F0EA;
    12→  --white:      #FFFFFF;
    13→  --ink:        #1A1714;
    14→  --ink-soft:   #3D3830;
    15→  --ink-muted:  #8A7F72;
    16→  --ink-light:  #B5ADA3;
    17→  --rule:       #DDD8CE;
    18→  --rule-dark:  #C4BDB3;
    19→  --forest:     #1B4332;
    20→  --forest-mid: #2D6A4F;
    21→  --forest-lt:  #EAF4EE;
    22→  --sienna:     #B5390A;
    23→  --sienna-lt:  #FDF0EB;
    24→  --amber:      #B45309;
    25→  --amber-lt:   #FEF3C7;
    26→  --cobalt:     #1E3A8A;
    27→  --cobalt-lt:  #EFF6FF;
    28→  --plum:       #6B21A8;
    29→  --plum-lt:    #FAF5FF;
    30→  --teal:       #0F766E;
    31→  --teal-lt:    #F0FDFA;
    32→  --rose:       #9F1239;
    33→  --rose-lt:    #FFF1F2;
    34→}
    35→*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
    36→html{scroll-behavior:smooth;}
    37→body{font-family:'DM Sans',sans-serif;background:var(--paper);color:var(--ink);min-height:100vh;-webkit-font-smoothing:antialiased;}
    38→
    39→/* MASTHEAD */
    40→.masthead{background:var(--forest);color:#fff;padding:0 48px;display:flex;align-items:center;justify-content:space-between;height:40px;font-family:'IBM Plex Mono',monospace;font-size:10px;letter-spacing:1.5px;text-transform:uppercase;}
    41→.masthead-side{opacity:.5;}
    42→.masthead-center{display:flex;align-items:center;gap:14px;opacity:.7;}
    43→.mdot{width:4px;height:4px;border-radius:50%;background:#86EFAC;}
    44→
    45→/* HERO */
    46→.hero{background:var(--white);border-bottom:2px solid var(--ink);padding:68px 48px 56px;position:relative;overflow:hidden;}
    47→.hero::after{content:'';position:absolute;top:0;right:0;width:38%;height:100%;background:repeating-linear-gradient(90deg,transparent,transparent 38px,var(--rule) 38px,var(--rule) 39px);opacity:.45;pointer-events:none;}
    48→.hero-inner{max-width:1180px;margin:0 auto;position:relative;z-index:1;}
    49→.eyebrow{font-family:'IBM Plex Mono',monospace;font-size:10px;letter-spacing:3px;text-transform:uppercase;color:var(--sienna);margin-bottom:18px;display:flex;align-items:center;gap:10px;}
    50→.eyebrow::before{content:'';display:block;width:28px;height:2px;background:var(--sienna);}
    51→h1{font-family:'Playfair Display',serif;font-size:clamp(3rem,6vw,5rem);font-weight:900;line-height:1.0;color:var(--ink);letter-spacing:-2px;margin-bottom:18px;}
    52→h1 em{font-style:italic;color:var(--forest);}
    53→.hero-rule{width:56px;height:3px;background:var(--ink);margin:22px 0;}
    54→.hero-desc{font-size:14.5px;color:var(--ink-soft);line-height:1.78;max-width:520px;font-weight:300;}
    55→.hero-stats{display:flex;gap:0;margin-top:42px;border:1px solid var(--rule-dark);width:fit-content;background:var(--paper);}
    56→.hstat{padding:16px 30px;border-right:1px solid var(--rule-dark);text-align:center;}
    57→.hstat:last-child{border-right:none;}
    58→.hstat-val{font-family:'Playfair Display',serif;font-size:1.9rem;font-weight:700;color:var(--ink);display:block;line-height:1;}
    59→.hstat-lbl{font-family:'IBM Plex Mono',monospace;font-size:9px;letter-spacing:1.5px;text-transform:uppercase;color:var(--ink-muted);display:block;margin-top:4px;}
    60→
    61→/* CONTROLS */
    62→.controls{position:sticky;top:0;z-index:200;background:var(--white);border-bottom:1.5px solid var(--ink);padding:11px 48px;display:flex;align-items:center;gap:9px;flex-wrap:wrap;box-shadow:0 2px 14px rgba(26,23,20,.07);}
    63→.swrap{position:relative;flex:1;min-width:170px;max-width:300px;}
    64→.sicon{position:absolute;left:10px;top:50%;transform:translateY(-50%);color:var(--ink-light);font-size:13px;pointer-events:none;}
    65→input[type=search]{width:100%;background:var(--paper);border:1px solid var(--rule-dark);color:var(--ink);font-family:'IBM Plex Mono',monospace;font-size:11px;padding:8px 12px 8px 28px;outline:none;border-radius:2px;transition:border-color .18s,box-shadow .18s;letter-spacing:.3px;}
    66→input[type=search]:focus{border-color:var(--forest);box-shadow:0 0 0 3px rgba(27,67,50,.08);}
    67→input[type=search]::placeholder{color:var(--ink-light);}
    68→.fbtn{font-family:'IBM Plex Mono',monospace;font-size:10px;letter-spacing:1px;text-transform:uppercase;background:var(--paper);border:1px solid var(--rule-dark);color:var(--ink-muted);padding:7px 13px;cursor:pointer;border-radius:2px;transition:all .14s;white-space:nowrap;}
    69→.fbtn:hover{background:var(--page);color:var(--ink);border-color:var(--ink-muted);}
    70→.fbtn.active{background:var(--forest);border-color:var(--forest);color:#fff;}
    71→.clabel{margin-left:auto;font-family:'IBM Plex Mono',monospace;font-size:10px;color:var(--ink-muted);white-space:nowrap;}
    72→
    73→/* WRAPPER */
    74→.wrapper{max-width:1220px;margin:0 auto;padding:0 48px 100px;}
    75→
    76→/* SECTION HEADS */
    77→.sh{display:flex;align-items:center;gap:18px;padding:50px 0 22px;}
    78→.snum{font-family:'Playfair Display',serif;font-style:italic;font-size:11px;color:var(--ink-light);white-space:nowrap;}
    79→.stitle{font-family:'IBM Plex Mono',monospace;font-size:10px;letter-spacing:3px;text-transform:uppercase;color:var(--ink-muted);white-space:nowrap;}
    80→.srule{flex:1;height:1px;background:var(--rule-dark);}
    81→
    82→/* TABLE */
    83→.tscroll{overflow-x:auto;border:1.5px solid var(--ink);border-radius:2px;}
    84→table{width:100%;border-collapse:collapse;background:var(--white);font-size:12.5px;}
    85→thead{background:var(--ink);color:#fff;}
    86→th{font-family:'IBM Plex Mono',monospace;font-size:9px;letter-spacing:2px;text-transform:uppercase;padding:13px 16px;text-align:left;font-weight:500;white-space:nowrap;}
    87→tbody tr{border-bottom:1px solid var(--rule);transition:background .12s;}
    88→tbody tr:last-child{border-bottom:none;}
    89→tbody tr:hover{background:var(--forest-lt);}
    90→td{padding:12px 16px;vertical-align:middle;font-size:12.5px;color:var(--ink-soft);}
    91→.tdn{font-family:'Playfair Display',serif;font-weight:700;font-size:14px;color:var(--ink);}
    92→.tdn small{display:block;font-family:'DM Sans',sans-serif;font-size:10px;color:var(--ink-muted);font-weight:400;margin-top:2px;}
    93→
    94→/* TAGS */
    95→.tag{display:inline-block;font-family:'IBM Plex Mono',monospace;font-size:8.5px;font-weight:600;letter-spacing:1px;text-transform:uppercase;padding:3px 7px;border-radius:2px;margin:1px 2px 1px 0;white-space:nowrap;}
    96→.tag-general  {background:var(--forest-lt);color:var(--forest);}
    97→.tag-code     {background:var(--plum-lt);color:var(--plum);}
    98→.tag-reasoning{background:var(--cobalt-lt);color:var(--cobalt);}
    99→.tag-vision   {background:var(--sienna-lt);color:var(--sienna);}
   100→.tag-embed    {background:var(--amber-lt);color:var(--amber);}
   101→.tag-edge     {background:var(--teal-lt);color:var(--teal);}
   102→.tag-multilang{background:var(--rose-lt);color:var(--rose);}
   103→
   104→/* CARDS */
   105→.mgrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(360px,1fr));gap:18px;}
   106→.mcard{background:var(--white);border:1px solid var(--rule-dark);border-left:4px solid var(--ca,var(--forest));border-radius:2px;padding:22px 24px;transition:box-shadow .2s,transform .2s;opacity:0;animation:fadeUp .45s ease forwards;}
   107→.mcard:hover{box-shadow:0 8px 32px rgba(26,23,20,.09);transform:translateY(-2px);}
   108→@keyframes fadeUp{from{opacity:0;transform:translateY(14px);}to{opacity:1;transform:translateY(0);}}
   109→.cnum{font-family:'Playfair Display',serif;font-style:italic;font-size:11px;color:var(--ink-light);margin-bottom:8px;}
   110→.cname{font-family:'Playfair Display',serif;font-size:1.2rem;font-weight:700;color:var(--ink);line-height:1.2;margin-bottom:3px;}
   111→.cauthor{font-family:'IBM Plex Mono',monospace;font-size:9.5px;color:var(--ink-muted);margin-bottom:13px;}
   112→.cdiv{height:1px;background:var(--rule);margin:13px 0;}
   113→.cdesc{font-size:13px;color:var(--ink-soft);line-height:1.72;margin-bottom:15px;font-weight:300;}
   114→.ctags{margin-bottom:14px;}
   115→.igrid{display:grid;grid-template-columns:1fr 1fr;gap:7px;margin-bottom:14px;}
   116→.icell{background:var(--paper);border:1px solid var(--rule);border-radius:2px;padding:8px 10px;}
   117→.ilbl{font-family:'IBM Plex Mono',monospace;font-size:8.5px;letter-spacing:1.5px;text-transform:uppercase;color:var(--ink-muted);margin-bottom:3px;}
   118→.ival{font-family:'IBM Plex Mono',monospace;font-size:12px;font-weight:600;color:var(--ink);}
   119→.ival.hi{color:var(--forest-mid);}
   120→.dh{font-family:'IBM Plex Mono',monospace;font-size:8.5px;letter-spacing:2px;text-transform:uppercase;color:var(--ink-muted);margin-bottom:8px;}
   121→.drow{display:flex;gap:9px;margin-bottom:6px;font-size:12px;line-height:1.5;}
   122→.dpip{width:14px;height:14px;border-radius:50%;background:var(--ca,var(--forest));flex-shrink:0;margin-top:2px;display:flex;align-items:center;justify-content:center;}
   123→.dpip::after{content:'';width:5px;height:5px;border-radius:50%;background:#fff;}
   124→.dco{font-weight:600;color:var(--ink);}
   125→.dctx{color:var(--ink-muted);font-weight:300;}
   126→.cfoot{margin-top:15px;padding-top:11px;border-top:1px solid var(--rule);display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:5px;}
   127→.lbadge{font-family:'IBM Plex Mono',monospace;font-size:9px;padding:3px 8px;border-radius:2px;letter-spacing:.5px;}
   128→.lopen  {background:var(--forest-lt);color:var(--forest);border:1px solid rgba(27,67,50,.2);}
   129→.lcomm  {background:var(--cobalt-lt);color:var(--cobalt);border:1px solid rgba(30,58,138,.2);}
   130→.lrestr {background:var(--sienna-lt);color:var(--sienna);border:1px solid rgba(181,57,10,.2);}
   131→.lres   {background:var(--amber-lt);color:var(--amber);border:1px solid rgba(180,83,9,.2);}
   132→.cdate{font-family:'IBM Plex Mono',monospace;font-size:9px;color:var(--ink-light);}
   133→
   134→/* VERIFY */
   135→.vbox{background:var(--white);border:1.5px solid var(--ink);border-radius:2px;overflow:hidden;}
   136→.vhead{background:var(--ink);color:#fff;padding:14px 28px;font-family:'Playfair Display',serif;font-size:1rem;font-weight:600;display:flex;align-items:center;gap:12px;}
   137→.vbody{padding:28px;}
   138→.vintro{font-size:13px;color:var(--ink-muted);margin-bottom:18px;font-weight:300;line-height:1.68;}
   139→.cmdblock{background:var(--paper);border:1px solid var(--rule-dark);border-left:3px solid var(--forest);border-radius:2px;padding:16px 20px;margin-bottom:12px;font-family:'IBM Plex Mono',monospace;font-size:12px;line-height:1.95;overflow-x:auto;white-space:pre;}
   140→.cc{color:var(--ink-light);font-style:italic;}
   141→.ck{color:var(--forest);font-weight:600;}
   142→.cs{color:var(--sienna);}
   143→.vnotes{display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:20px;}
   144→.ncard{background:var(--paper);border:1px solid var(--rule);border-radius:2px;padding:16px 18px;}
   145→.nth{font-family:'IBM Plex Mono',monospace;font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--ink-muted);margin-bottom:10px;display:flex;align-items:center;gap:7px;}
   146→.nth::before{content:'';width:8px;height:8px;border-radius:50%;background:var(--forest);flex-shrink:0;}
   147→.nth.warn::before{background:var(--sienna);}
   148→.ncard ul{list-style:none;font-size:12.5px;color:var(--ink-soft);line-height:1.72;font-weight:300;}
   149→.ncard a{color:var(--forest);text-decoration:none;font-family:'IBM Plex Mono',monospace;font-size:11px;}
   150→.ncard a:hover{text-decoration:underline;}
   151→
   152→/* UTILS */
   153→.hidden{display:none!important;}
   154→::-webkit-scrollbar{width:6px;height:6px;}
   155→::-webkit-scrollbar-track{background:var(--paper);}
   156→::-webkit-scrollbar-thumb{background:var(--rule-dark);border-radius:3px;}
   157→::-webkit-scrollbar-thumb:hover{background:var(--ink-light);}
   158→@media(max-width:768px){
   159→  .masthead{padding:0 16px;}.hero{padding:44px 20px 40px;}.controls{padding:10px 16px;}.wrapper{padding:0 16px 60px;}
   160→  .mgrid{grid-template-columns:1fr;}.vnotes{grid-template-columns:1fr;}
   161→  .hero-stats{flex-direction:column;width:100%;}.hstat{border-right:none;border-bottom:1px solid var(--rule-dark);text-align:left;padding:12px 20px;}
   162→  h1{font-size:2.5rem;letter-spacing:-1px;}
   163→}
   164→</style>
   165→</head>
   166→<body>
   167→
   168→<div class="masthead">
   169→  <span class="masthead-side">Ollama Research Reference</span>
   170→  <div class="masthead-center"><div class="mdot"></div><span>Updated March 2025</span><div class="mdot"></div></div>
   171→  <span class="masthead-side">Vol. I · 2025 Edition</span>
   172→</div>
   173→
   174→<header class="hero">
   175→  <div class="hero-inner">
   176→    <div class="eyebrow">Comprehensive Reference · Local AI Models</div>
