/* ─── Claude Code CTA ─── */
.hero-cc-cta {
  margin-top: 28px;
  display: flex;
  justify-content: center;
}
.cc-cta-btn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 13px 26px;
  background: var(--bg-card);
  border: 1px solid var(--border-strong);
  border-radius: 14px;
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--ink-2);
  text-decoration: none;
  transition: all 0.25s;
  box-shadow: var(--shadow-sm);
  letter-spacing: 0.3px;
  max-width: 100%;
}
.cc-cta-btn:hover {
  border-color: var(--green);
  color: var(--green);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}
.cc-cta-btn .cta-arrow {
  opacity: 0.45;
  transition: transform 0.2s, opacity 0.2s;
  flex-shrink: 0;
}
.cc-cta-btn:hover .cta-arrow {
  opacity: 1;
  transform: translateX(4px);
}
.cc-cta-label { word-break: break-word; }

/* ─── Footer ─── */
footer {
  position: relative;
  z-index: 1;
  text-align: center;

